// Publisher Program QBR data pack (advertiser-style structure)
const NODE_PAYLOAD = 'yoy data extraction1';
const NODE_CURRENT = 'Collect Publisher Current';
const NODE_PREVIOUS = 'Collect Publisher Previous';
const NODE_CURRENT_DIGITAL_WALLETS = 'Collect Publisher Digital Wallets Current';
const NODE_PREVIOUS_DIGITAL_WALLETS = 'Collect Publisher Digital Wallets Previous';

const LOCALE = 'en-GB';
const DISPLAY_TOP_LIMIT = 12;
const MOVER_LIMIT = 10;
const BRAND_NEW_LIMIT = 3;
const SIGNAL_LIMIT = 10;
const RISK_LIMIT = 10;
const SUPPORTED_CURRENCIES = new Set(['GBP', 'EUR', 'USD', 'AUD', 'SEK', 'NOK', 'DKK', 'ISK', 'PLN']);

function safeNum(v) {
  if (v === null || v === undefined || v === '') return 0;
  if (typeof v === 'number') return Number.isFinite(v) ? v : 0;

  let s = String(v).trim().replace(/[^\d,.-]/g, '').replace(/\s+/g, '');
  if (!s) return 0;

  const lastComma = s.lastIndexOf(',');
  const lastDot = s.lastIndexOf('.');

  if (lastComma > -1 && lastDot > -1) {
    if (lastComma > lastDot) {
      s = s.replace(/\./g, '');
      const i = s.lastIndexOf(',');
      s = s.slice(0, i).replace(/,/g, '') + '.' + s.slice(i + 1);
    } else {
      s = s.replace(/,/g, '');
    }
  } else if (lastComma > -1) {
    const decDigits = s.length - lastComma - 1;
    if (decDigits >= 1 && decDigits <= 2) {
      s = s.slice(0, lastComma).replace(/,/g, '') + '.' + s.slice(lastComma + 1);
    } else {
      s = s.replace(/,/g, '');
    }
  } else if (lastDot > -1) {
    const decDigits = s.length - lastDot - 1;
    if (!(decDigits >= 1 && decDigits <= 2)) s = s.replace(/\./g, '');
  }

  const n = Number(s);
  return Number.isFinite(n) ? n : 0;
}

function normalizeCurrencyCode(code) {
  const c = String(code || '').trim().toUpperCase();
  return SUPPORTED_CURRENCIES.has(c) ? c : '';
}

function getCurrencySymbol(code) {
  switch (String(code || '').toUpperCase()) {
    case 'GBP': return '\u00A3';
    case 'EUR': return '\u20AC';
    case 'USD': return '$';
    case 'AUD': return 'A$';
    case 'PLN': return 'z\u0142';
    case 'SEK':
    case 'NOK':
    case 'DKK':
    case 'ISK': return 'kr';
    default: return '';
  }
}

function fmtInt(v) {
  return Math.round(safeNum(v)).toLocaleString(LOCALE);
}

function fmtMoney0(v, symbol) {
  const n = Math.round(safeNum(v));
  const sign = n < 0 ? '-' : '';
  return sign + symbol + Math.abs(n).toLocaleString(LOCALE);
}

function fmtMoney2(v, symbol) {
  const n = safeNum(v);
  const sign = n < 0 ? '-' : '';
  return sign + symbol + Math.abs(n).toLocaleString(LOCALE, {
    minimumFractionDigits: 2,
    maximumFractionDigits: 2,
  });
}

function fmtPct(v) {
  if (v === null || v === undefined || Number.isNaN(v)) return 'N/A';
  const n = Number(v);
  const sign = n > 0 ? '+' : '';
  return sign + n.toFixed(1) + '%';
}

function varianceTone(v) {
  if (v === null || v === undefined || Number.isNaN(v)) return 'na';
  const n = Number(v);
  if (n > 0) return 'positive';
  if (n < 0) return 'negative';
  return 'neutral';
}

function varianceColorHex(v) {
  const tone = varianceTone(v);
  if (tone === 'positive') return '#1a7f37';
  if (tone === 'negative') return '#d93025';
  return '#fbbc04';
}

function fmtVarianceCell(v) {
  const base = fmtPct(v);
  const tone = varianceTone(v);
  if (tone === 'positive') return '▲ ' + base;
  if (tone === 'negative') return '▼ ' + base;
  return base;
}

function fmtAbsPct(v) {
  if (v === null || v === undefined || Number.isNaN(v)) return 'N/A';
  return Number(v).toFixed(1) + '%';
}

function yoyPct(current, previous) {
  if (!previous) return null;
  return ((current - previous) / previous) * 100;
}

function getRows(nodeJson) {
  if (!nodeJson || typeof nodeJson !== 'object') return [];
  if (Array.isArray(nodeJson.allItems)) return nodeJson.allItems;
  if (Array.isArray(nodeJson.items)) return nodeJson.items;
  if (Array.isArray(nodeJson.data)) return nodeJson.data;
  if (Array.isArray(nodeJson.rows)) return nodeJson.rows;
  return [];
}

function pickProgramId(item) {
  const candidates = [
    item.programId,
    item.program && item.program.id,
    item.campaignId,
    item.offerId,
    item.advertiserProgramId,
    item.programID,
    item.id,
  ];
  for (const c of candidates) {
    const value = String(c || '').trim();
    if (value) return value;
  }
  return '';
}

function pickSourceId(item) {
  const candidates = [
    item.sourceId,
    item.sourceID,
    item.source && item.source.id,
    item.siteId,
    item.siteID,
    item.publisherSiteId,
    item.affiliateSiteId,
  ];
  for (const c of candidates) {
    const value = String(c || '').trim();
    if (value) return value;
  }
  return '';
}

function pickProgramName(item, fallbackId) {
  const candidates = [
    item.programName,
    item.program && item.program.name,
    item.campaignName,
    item.offerName,
    item.programDisplayName,
    item.name,
  ];
  for (const c of candidates) {
    const value = String(c || '').trim();
    if (value) return value;
  }
  return fallbackId ? ('Program ' + fallbackId) : 'Unknown Program';
}

function findNumericByKeys(obj, keys) {
  if (!obj || typeof obj !== 'object') return 0;
  let best = 0;
  const byLower = Object.fromEntries(Object.keys(obj).map((k) => [k.toLowerCase(), k]));
  for (const key of keys) {
    const rawKey = byLower[String(key).toLowerCase()];
    if (!rawKey) continue;
    best = Math.max(best, safeNum(obj[rawKey]));
  }
  return best;
}

function collectCommissionLikeNumbers(node, out, depth = 0) {
  if (depth > 4 || node === null || node === undefined) return;
  if (typeof node === 'number' || typeof node === 'string') {
    const n = safeNum(node);
    if (n > 0) out.push(n);
    return;
  }
  if (Array.isArray(node)) {
    for (const child of node) collectCommissionLikeNumbers(child, out, depth + 1);
    return;
  }
  if (typeof node !== 'object') return;

  for (const [key, value] of Object.entries(node)) {
    const k = String(key || '').toLowerCase();
    if (k.includes('rate') || k.includes('ratio') || k.includes('percent') || k.includes('pct')) continue;
    const looksCommissionLike = k.includes('commission') || k.includes('earning') || k.includes('payout') || k.includes('remuneration') || k.includes('reward');
    if (looksCommissionLike) {
      const n = safeNum(value);
      if (n > 0) out.push(n);
    }
    if (value && typeof value === 'object') collectCommissionLikeNumbers(value, out, depth + 1);
  }
}

function pickDigitalWalletAmount(item) {
  const amountObj = (item.amount && typeof item.amount === 'object')
    ? item.amount
    : ((item.value && typeof item.value === 'object') ? item.value : {});
  return Math.max(
    safeNum(item.digitalWallet),
    safeNum(item.digitalWallets),
    safeNum(item.digitalWalletAmount),
    safeNum(item.digitalWalletCommission),
    safeNum(item.digitalWalletEarnings),
    safeNum(item.wallet),
    safeNum(item.walletAmount),
    safeNum(item.walletCommission),
    safeNum(item.walletEarnings),
    safeNum(item.amount),
    safeNum(item.amountValue),
    safeNum(item.commissionAmount),
    safeNum(item.publisherAmount),
    safeNum(item.paymentAmount),
    safeNum(item.payableAmount),
    safeNum(item.netAmount),
    safeNum(amountObj.amount),
    safeNum(amountObj.value),
    findNumericByKeys(item, [
      'digitalWallet',
      'digitalWallets',
      'digital_wallet',
      'digital_wallets',
      'digitalWalletAmount',
      'digitalWalletCommission',
      'digitalWalletEarnings',
      'walletAmount',
      'walletCommission',
      'walletEarnings',
      'amount',
      'amountValue',
      'commissionAmount',
      'publisherAmount',
      'paymentAmount',
      'payableAmount',
      'netAmount',
    ])
  );
}

function buildProgramKey(item) {
  const programId = pickProgramId(item);
  if (programId) return 'program:' + programId;
  const programName = pickProgramName(item, '').toLowerCase();
  if (programName) return 'name:' + programName;
  const sourceId = pickSourceId(item);
  if (sourceId) return 'source:' + sourceId;
  return '';
}

function mergeDigitalWalletRows(metricRows, walletRows) {
  const walletByKey = new Map();

  for (const wallet of walletRows || []) {
    if (!wallet || typeof wallet !== 'object') continue;
    const key = buildProgramKey(wallet);
    if (!key) continue;
    const digitalWalletAmount = pickDigitalWalletAmount(wallet);
    if (digitalWalletAmount <= 0) continue;
    const programId = pickProgramId(wallet);
    const existing = walletByKey.get(key) || {
      programId: programId || '-',
      programName: pickProgramName(wallet, programId),
      sourceId: pickSourceId(wallet),
      digitalWalletAmount: 0,
    };
    existing.digitalWalletAmount += digitalWalletAmount;
    walletByKey.set(key, existing);
  }

  const merged = (metricRows || []).map((row) => {
    const key = buildProgramKey(row || {});
    const wallet = key ? walletByKey.get(key) : null;
    if (!wallet) return row;
    walletByKey.delete(key);
    return {
      ...row,
      digitalWalletAmount: Math.max(safeNum(row.digitalWalletAmount), wallet.digitalWalletAmount),
      digitalWallet: Math.max(safeNum(row.digitalWallet), wallet.digitalWalletAmount),
      walletAmount: Math.max(safeNum(row.walletAmount), wallet.digitalWalletAmount),
    };
  });

  for (const wallet of walletByKey.values()) {
    merged.push({
      programId: wallet.programId,
      programName: wallet.programName,
      sourceId: wallet.sourceId,
      clicks: 0,
      sales: 0,
      orderValue: 0,
      publisherCommission: 0,
      totalCommission: wallet.digitalWalletAmount,
      digitalWalletAmount: wallet.digitalWalletAmount,
      digitalWallet: wallet.digitalWalletAmount,
      walletAmount: wallet.digitalWalletAmount,
    });
  }

  return merged;
}

function findDigitalWalletValue(item, commissionObj, totalCommission, publisherCommission) {
  const directDigitalWallet = Math.max(
    safeNum(item.digitalWallet),
    safeNum(item.digitalWallets),
    safeNum(item.digitalWalletAmount),
    safeNum(item.digitalWalletCommission),
    safeNum(item.digitalWalletEarnings),
    safeNum(item.wallet),
    safeNum(item.walletAmount),
    safeNum(commissionObj.digitalWallet),
    safeNum(commissionObj.digitalWallets),
    safeNum(commissionObj.digitalWalletAmount),
    safeNum(commissionObj.digitalWalletCommission),
    safeNum(commissionObj.digitalWalletEarnings),
    findNumericByKeys(item, [
      'digitalWallet',
      'digitalWallets',
      'digital_wallet',
      'digital_wallets',
      'digitalWalletAmount',
      'digitalWalletCommission',
      'digitalWalletEarnings',
      'wallet',
      'walletAmount',
      'walletCommission',
      'walletEarnings',
    ])
  );
  const inferredDigitalWallet = Math.max(0, safeNum(totalCommission) - safeNum(publisherCommission));
  return Math.max(directDigitalWallet, inferredDigitalWallet);
}

function parseMetrics(item) {
  const commissionObj = (item.salesCommission && typeof item.salesCommission === 'object')
    ? item.salesCommission
    : ((item.commission && typeof item.commission === 'object') ? item.commission : {});
  const commissionValue = (typeof item.commission === 'number' || typeof item.commission === 'string')
    ? safeNum(item.commission)
    : 0;

  const clicks = safeNum(item.clicks);
  const sales = safeNum(item.sales) + safeNum(item.iSales);
  const orderValue = Math.max(
    safeNum(item.orderValue),
    safeNum(item.salesOrderValue),
    safeNum(item.iSalesOrderValue),
    safeNum(item.eventOrderValue)
  );

  const directPublisherCommission = Math.max(
    safeNum(item.publisherCommission),
    safeNum(commissionObj.publisherCommission),
    findNumericByKeys(item, [
      'publisherCommission',
      'publisher_commission',
      'pubCommission',
      'publisherEarnings',
      'publisherReward',
      'eventPublisherCommission',
      'eventCommission',
      'salesCommissionPublisher',
      'commissionAmount',
      'commissionValue',
    ])
  );

  const directTotalCommission = Math.max(
    safeNum(item.totalCommission),
    safeNum(commissionObj.totalCommission),
    findNumericByKeys(item, [
      'totalCommission',
      'total_commission',
      'commissionTotal',
      'totalEarnings',
      'totalPayout',
      'networkCommission',
      'advertiserCommission',
      'salesCommissionTotal',
    ])
  );

  const discoveredCommissionNumbers = [];
  collectCommissionLikeNumbers(item.salesCommission, discoveredCommissionNumbers);
  collectCommissionLikeNumbers(item.commission, discoveredCommissionNumbers);
  collectCommissionLikeNumbers(item, discoveredCommissionNumbers);
  const discoveredCommissionMax = discoveredCommissionNumbers.length ? Math.max(...discoveredCommissionNumbers) : 0;

  const publisherCommission = Math.max(
    directPublisherCommission,
    commissionValue,
    discoveredCommissionMax
  );

  const totalCommission = Math.max(
    directTotalCommission,
    commissionValue,
    discoveredCommissionMax,
    publisherCommission
  );
  const digitalWallet = findDigitalWalletValue(item, commissionObj, totalCommission, publisherCommission);
  const totalEarnings = publisherCommission + digitalWallet;

  return { clicks, sales, orderValue, publisherCommission, totalCommission, digitalWallet, totalEarnings };
}

function aggregateByProgram(rows) {
  const map = new Map();

  for (const item of rows || []) {
    const programId = pickProgramId(item);
    const programName = pickProgramName(item, programId);
    const key = programId || programName.toLowerCase();
    const m = parseMetrics(item);

    if (!map.has(key)) {
      map.set(key, {
        key,
        programId: programId || '-',
        programName,
        clicks: 0,
        sales: 0,
        orderValue: 0,
        publisherCommission: 0,
        totalCommission: 0,
        digitalWallet: 0,
        totalEarnings: 0,
      });
    }

    const acc = map.get(key);
    acc.clicks += m.clicks;
    acc.sales += m.sales;
    acc.orderValue += m.orderValue;
    acc.publisherCommission += m.publisherCommission;
    acc.totalCommission += m.totalCommission;
    acc.digitalWallet += m.digitalWallet;
    acc.totalEarnings += m.totalEarnings;
  }

  return Array.from(map.values());
}

function aggregateTotals(programRows) {
  return (programRows || []).reduce((acc, row) => {
    acc.clicks += row.clicks;
    acc.sales += row.sales;
    acc.orderValue += row.orderValue;
    acc.publisherCommission += row.publisherCommission;
    acc.totalCommission += row.totalCommission;
    acc.digitalWallet += row.digitalWallet;
    acc.totalEarnings += row.totalEarnings;
    if (row.publisherCommission > 0) acc.programsWithCommission += 1;
    return acc;
  }, {
    clicks: 0,
    sales: 0,
    orderValue: 0,
    publisherCommission: 0,
    totalCommission: 0,
    digitalWallet: 0,
    totalEarnings: 0,
    programsWithCommission: 0,
  });
}

function buildMetricRow(metric, currentValue, previousValue, formatter) {
  const diff = safeNum(currentValue) - safeNum(previousValue);
  return {
    Metric: metric,
    Recent: formatter(currentValue),
    Previous: formatter(previousValue),
    Difference: formatter(diff),
    '% Variance': fmtPct(yoyPct(currentValue, previousValue)),
  };
}

const payload = $node[NODE_PAYLOAD] && $node[NODE_PAYLOAD].json && $node[NODE_PAYLOAD].json.payload ? $node[NODE_PAYLOAD].json.payload : {};
const currentRawRows = mergeDigitalWalletRows(
  getRows(($node[NODE_CURRENT] && $node[NODE_CURRENT].json) || {}),
  getRows(($node[NODE_CURRENT_DIGITAL_WALLETS] && $node[NODE_CURRENT_DIGITAL_WALLETS].json) || {})
);
const previousRawRows = mergeDigitalWalletRows(
  getRows(($node[NODE_PREVIOUS] && $node[NODE_PREVIOUS].json) || {}),
  getRows(($node[NODE_PREVIOUS_DIGITAL_WALLETS] && $node[NODE_PREVIOUS_DIGITAL_WALLETS].json) || {})
);

const currentPrograms = aggregateByProgram(currentRawRows);
const previousPrograms = aggregateByProgram(previousRawRows);

const previousByKey = new Map(previousPrograms.map((row) => [row.key, row]));

const comparedPrograms = currentPrograms.map((cur) => {
  const prev = previousByKey.get(cur.key) || {
    clicks: 0,
    sales: 0,
    orderValue: 0,
    publisherCommission: 0,
    totalCommission: 0,
    digitalWallet: 0,
    totalEarnings: 0,
  };

  return {
    ...cur,
    prevClicks: prev.clicks,
    prevSales: prev.sales,
    prevOrderValue: prev.orderValue,
    prevPublisherCommission: prev.publisherCommission,
    prevTotalCommission: prev.totalCommission,
    prevDigitalWallet: prev.digitalWallet,
    prevTotalEarnings: prev.totalEarnings,
    clicksYoYAbs: cur.clicks - prev.clicks,
    salesYoYAbs: cur.sales - prev.sales,
    orderValueYoYAbs: cur.orderValue - prev.orderValue,
    publisherCommissionYoYAbs: cur.publisherCommission - prev.publisherCommission,
    digitalWalletYoYAbs: cur.digitalWallet - prev.digitalWallet,
    totalEarningsYoYAbs: cur.totalEarnings - prev.totalEarnings,
    clicksYoYPct: yoyPct(cur.clicks, prev.clicks),
    salesYoYPct: yoyPct(cur.sales, prev.sales),
    orderValueYoYPct: yoyPct(cur.orderValue, prev.orderValue),
    publisherCommissionYoYPct: yoyPct(cur.publisherCommission, prev.publisherCommission),
    digitalWalletYoYPct: yoyPct(cur.digitalWallet, prev.digitalWallet),
    totalEarningsYoYPct: yoyPct(cur.totalEarnings, prev.totalEarnings),
  };
});

const brandNewPrograms = currentPrograms
  .filter((cur) => {
    const prev = previousByKey.get(cur.key);
    const hasCurrentActivity = cur.clicks > 0 || cur.sales > 0 || cur.orderValue > 0 || cur.publisherCommission > 0 || cur.totalEarnings > 0;
    if (!hasCurrentActivity) return false;
    if (!prev) return true;
    return prev.clicks <= 0 && prev.sales <= 0 && prev.orderValue <= 0 && prev.publisherCommission <= 0 && prev.totalEarnings <= 0;
  })
  .sort((a, b) => {
    const byOv = b.orderValue - a.orderValue;
    if (byOv !== 0) return byOv;
    const bySales = b.sales - a.sales;
    if (bySales !== 0) return bySales;
    return b.totalEarnings - a.totalEarnings;
  })
  .slice(0, BRAND_NEW_LIMIT);

const requestedCurrency = normalizeCurrencyCode(payload.currencyCode);
const apiCurrency = normalizeCurrencyCode((currentRawRows[0] && currentRawRows[0].reportCurrencyCode) || (previousRawRows[0] && previousRawRows[0].reportCurrencyCode));
const currencyCode = requestedCurrency || apiCurrency || 'EUR';
const currencySymbol = getCurrencySymbol(currencyCode);

const currentTotals = aggregateTotals(currentPrograms);
const previousTotals = aggregateTotals(previousPrograms);

const currentConvRate = currentTotals.clicks ? (currentTotals.sales / currentTotals.clicks) * 100 : 0;
const previousConvRate = previousTotals.clicks ? (previousTotals.sales / previousTotals.clicks) * 100 : 0;
const currentAov = currentTotals.sales ? (currentTotals.orderValue / currentTotals.sales) : 0;
const previousAov = previousTotals.sales ? (previousTotals.orderValue / previousTotals.sales) : 0;
const currentEpc = currentTotals.clicks ? (currentTotals.publisherCommission / currentTotals.clicks) : 0;
const previousEpc = previousTotals.clicks ? (previousTotals.publisherCommission / previousTotals.clicks) : 0;

const currentProgramCount = currentPrograms.length;
const previousProgramCount = previousPrograms.length;

const kpiVarianceRaw = {
  clicks: yoyPct(currentTotals.clicks, previousTotals.clicks),
  sales: yoyPct(currentTotals.sales, previousTotals.sales),
  convRate: yoyPct(currentConvRate, previousConvRate),
  aov: yoyPct(currentAov, previousAov),
  epc: yoyPct(currentEpc, previousEpc),
  orderValue: yoyPct(currentTotals.orderValue, previousTotals.orderValue),
  publisherCommission: yoyPct(currentTotals.publisherCommission, previousTotals.publisherCommission),
  digitalWallet: yoyPct(currentTotals.digitalWallet, previousTotals.digitalWallet),
  totalEarnings: yoyPct(currentTotals.totalEarnings, previousTotals.totalEarnings),
  activePrograms: yoyPct(currentProgramCount, previousProgramCount),
  programsWithCommission: yoyPct(currentTotals.programsWithCommission, previousTotals.programsWithCommission),
};

const publisherPerformanceSummaryTable = [
  buildMetricRow('Conversions', currentTotals.sales, previousTotals.sales, fmtInt),
  buildMetricRow('Conversion Rate', currentConvRate, previousConvRate, fmtAbsPct),
  buildMetricRow('Order Value', currentTotals.orderValue, previousTotals.orderValue, (v) => fmtMoney0(v, currencySymbol)),
  buildMetricRow('Publisher Commission', currentTotals.publisherCommission, previousTotals.publisherCommission, (v) => fmtMoney0(v, currencySymbol)),
  buildMetricRow('Digital Wallet', currentTotals.digitalWallet, previousTotals.digitalWallet, (v) => fmtMoney0(v, currencySymbol)),
  buildMetricRow('Total Earnings', currentTotals.totalEarnings, previousTotals.totalEarnings, (v) => fmtMoney0(v, currencySymbol)),
  buildMetricRow('Active Programs', currentProgramCount, previousProgramCount, fmtInt),
];

const kpiSummaryTable = [
  {
    Period: 'Recent',
    Conversions: fmtInt(currentTotals.sales),
    'Conv Rate': fmtAbsPct(currentConvRate),
    'Order Value': fmtMoney0(currentTotals.orderValue, currencySymbol),
    'Publisher Commission': fmtMoney0(currentTotals.publisherCommission, currencySymbol),
    'Digital Wallet': fmtMoney0(currentTotals.digitalWallet, currencySymbol),
    'Total Earnings': fmtMoney0(currentTotals.totalEarnings, currencySymbol),
    'Active Programs': fmtInt(currentProgramCount),
    'Programs w/ Commission': fmtInt(currentTotals.programsWithCommission),
  },
  {
    Period: 'Previous',
    Conversions: fmtInt(previousTotals.sales),
    'Conv Rate': fmtAbsPct(previousConvRate),
    'Order Value': fmtMoney0(previousTotals.orderValue, currencySymbol),
    'Publisher Commission': fmtMoney0(previousTotals.publisherCommission, currencySymbol),
    'Digital Wallet': fmtMoney0(previousTotals.digitalWallet, currencySymbol),
    'Total Earnings': fmtMoney0(previousTotals.totalEarnings, currencySymbol),
    'Active Programs': fmtInt(previousProgramCount),
    'Programs w/ Commission': fmtInt(previousTotals.programsWithCommission),
  },
  {
    Period: 'Difference',
    Conversions: fmtInt(currentTotals.sales - previousTotals.sales),
    'Conv Rate': fmtAbsPct(currentConvRate - previousConvRate),
    'Order Value': fmtMoney0(currentTotals.orderValue - previousTotals.orderValue, currencySymbol),
    'Publisher Commission': fmtMoney0(currentTotals.publisherCommission - previousTotals.publisherCommission, currencySymbol),
    'Digital Wallet': fmtMoney0(currentTotals.digitalWallet - previousTotals.digitalWallet, currencySymbol),
    'Total Earnings': fmtMoney0(currentTotals.totalEarnings - previousTotals.totalEarnings, currencySymbol),
    'Active Programs': fmtInt(currentProgramCount - previousProgramCount),
    'Programs w/ Commission': fmtInt(currentTotals.programsWithCommission - previousTotals.programsWithCommission),
  },
  {
    Period: '% Variance',
    Conversions: fmtVarianceCell(kpiVarianceRaw.sales),
    'Conv Rate': fmtVarianceCell(kpiVarianceRaw.convRate),
    'Order Value': fmtVarianceCell(kpiVarianceRaw.orderValue),
    'Publisher Commission': fmtVarianceCell(kpiVarianceRaw.publisherCommission),
    'Digital Wallet': fmtVarianceCell(kpiVarianceRaw.digitalWallet),
    'Total Earnings': fmtVarianceCell(kpiVarianceRaw.totalEarnings),
    'Active Programs': fmtVarianceCell(kpiVarianceRaw.activePrograms),
    'Programs w/ Commission': fmtVarianceCell(kpiVarianceRaw.programsWithCommission),
  },
];

const kpiVarianceColorHintsTable = [
  { Metric: 'Conversions', 'Variance %': fmtPct(kpiVarianceRaw.sales), Tone: varianceTone(kpiVarianceRaw.sales), Color: varianceColorHex(kpiVarianceRaw.sales) },
  { Metric: 'Conv Rate', 'Variance %': fmtPct(kpiVarianceRaw.convRate), Tone: varianceTone(kpiVarianceRaw.convRate), Color: varianceColorHex(kpiVarianceRaw.convRate) },
