function compareProgramsByImpact(a, b) {
  const aLowSignal = a.sales <= 0 && a.orderValue <= 0 && a.publisherCommission <= 0 && a.totalEarnings <= 0;
  const bLowSignal = b.sales <= 0 && b.orderValue <= 0 && b.publisherCommission <= 0 && b.totalEarnings <= 0;
  if (aLowSignal !== bLowSignal) return aLowSignal ? 1 : -1;

  const byCommission = b.publisherCommission - a.publisherCommission;
  if (byCommission !== 0) return byCommission;
  const byTotalEarnings = b.totalEarnings - a.totalEarnings;
  if (byTotalEarnings !== 0) return byTotalEarnings;
  const byOrderValue = b.orderValue - a.orderValue;
  if (byOrderValue !== 0) return byOrderValue;
  const bySales = b.sales - a.sales;
  if (bySales !== 0) return bySales;
  return String(a.programName || '').localeCompare(String(b.programName || ''));
}

function toProgramBreakdownRow(r) {
