function buildMoversTable(metricKey, metricLabel, formatter) {
  const yoyAbsKey = metricKey + 'YoYAbs';
  const yoyPctKey = metricKey + 'YoYPct';

  const up = comparedPrograms
    .filter((r) => safeNum(r[yoyAbsKey]) > 0)
    .sort((a, b) => b[yoyAbsKey] - a[yoyAbsKey])
    .slice(0, MOVER_LIMIT)
    .map((r) => ({
      Direction: 'Up',
      'Program Name': r.programName,
      'Program ID': r.programId,
      [metricLabel]: formatter(r[metricKey]),
      'YoY Change': formatter(r[yoyAbsKey]),
      'YoY %': fmtPct(r[yoyPctKey]),
    }));

  const down = comparedPrograms
    .filter((r) => safeNum(r[yoyAbsKey]) < 0)
    .sort((a, b) => a[yoyAbsKey] - b[yoyAbsKey])
    .slice(0, MOVER_LIMIT)
    .map((r) => ({
      Direction: 'Down',
      'Program Name': r.programName,
      'Program ID': r.programId,
      [metricLabel]: formatter(r[metricKey]),
      'YoY Change': formatter(r[yoyAbsKey]),
      'YoY %': fmtPct(r[yoyPctKey]),
    }));

  if ((up.length || down.length) || metricKey !== 'publisherCommission') {
    return up.concat(down);
  }

  const topCurrent = comparedPrograms
    .slice()
    .sort((a, b) => {
      const byMetric = safeNum(b[metricKey]) - safeNum(a[metricKey]);
      if (byMetric !== 0) return byMetric;
      return safeNum(b.sales) - safeNum(a.sales);
    })
    .slice(0, MOVER_LIMIT)
    .map((r) => ({
      Direction: 'Up',
      'Program Name': r.programName,
      'Program ID': r.programId,
      [metricLabel]: formatter(r[metricKey]),
      'YoY Change': formatter(r[yoyAbsKey]),
      'YoY %': fmtPct(r[yoyPctKey]),
    }));

  const bottomCurrent = comparedPrograms
    .slice()
    .sort((a, b) => {
      const byMetric = safeNum(a[metricKey]) - safeNum(b[metricKey]);
      if (byMetric !== 0) return byMetric;
      return safeNum(a.sales) - safeNum(b.sales);
    })
    .slice(0, MOVER_LIMIT)
    .map((r) => ({
      Direction: 'Down',
      'Program Name': r.programName,
      'Program ID': r.programId,
      [metricLabel]: formatter(r[metricKey]),
      'YoY Change': formatter(r[yoyAbsKey]),
      'YoY %': fmtPct(r[yoyPctKey]),
    }));

  return topCurrent.concat(bottomCurrent);
}

