function normalizeIdList(input) {
  if (Array.isArray(input)) {
    return input.map((value) => String(value || '').trim()).filter(Boolean);
  }
  if (typeof input === 'string' && input.trim()) {
    return input.split(',').map((value) => value.trim()).filter(Boolean);
  }
  if (input !== null && input !== undefined && String(input).trim()) {
    return [String(input).trim()];
  }
  return [];
}

function extractSourceIdsFromEndpoint(url) {
  if (!url || typeof url !== 'string') return [];
  try {
    const parsed = new URL(url);
    return [
      parsed.searchParams.get('sourceID'),
      parsed.searchParams.get('sourceId'),
      parsed.searchParams.get('sourceid'),
    ].map((v) => String(v || '').trim()).filter(Boolean);
  } catch {
    return [];
  }
}

function toYyyyMmDd(input, fallbackDate) {
  const value = String(input || '').trim();
  if (value) {
    if (/^\d{8}$/.test(value)) return value;
    const digits = value.replace(/[^0-9]/g, '');
    if (digits.length === 8) return digits;
  }

  const date = fallbackDate instanceof Date ? fallbackDate : new Date(fallbackDate);
  const y = date.getUTCFullYear();
  const m = String(date.getUTCMonth() + 1).padStart(2, '0');
  const d = String(date.getUTCDate()).padStart(2, '0');
  return y + m + d;
}

function shiftYear(yyyymmdd, years) {
  const y = parseInt(String(yyyymmdd).slice(0, 4), 10) + years;
  const m = String(yyyymmdd).slice(4, 6);
  const d = String(yyyymmdd).slice(6, 8);
  return String(y) + m + d;
}

function formatYmd(yyyymmdd) {
  const s = String(yyyymmdd || '');
  if (!/^\d{8}$/.test(s)) return s;
  return s.slice(0, 4) + '-' + s.slice(4, 6) + '-' + s.slice(6, 8);
}

function parseDateParts(yyyymmdd) {
  const value = String(yyyymmdd || '');
  if (!/^\d{8}$/.test(value)) return null;

  const year = parseInt(value.slice(0, 4), 10);
  const month = parseInt(value.slice(4, 6), 10);
  const day = parseInt(value.slice(6, 8), 10);
  if (!year || month < 1 || month > 12 || day < 1 || day > 31) return null;

  return { year, month, day };
}

function formatDateParts(parts) {
  return String(parts.year).padStart(4, '0') + String(parts.month).padStart(2, '0') + String(parts.day).padStart(2, '0');
}

function firstDayOfNextMonth(parts) {
  if (parts.month === 12) {
    return { year: parts.year + 1, month: 1, day: 1 };
  }
  return { year: parts.year, month: parts.month + 1, day: 1 };
}

function normalizeDateRangeByInterval(fromYyyymmdd, toYyyymmdd, interval) {
  if (interval !== 'month') {
    return { fromDate: fromYyyymmdd, toDate: toYyyymmdd };
  }

  const fromParts = parseDateParts(fromYyyymmdd);
  const toParts = parseDateParts(toYyyymmdd);
  if (!fromParts || !toParts) {
    return { fromDate: fromYyyymmdd, toDate: toYyyymmdd };
  }

  const monthFrom = formatDateParts({ year: fromParts.year, month: fromParts.month, day: 1 });
  let monthTo = toParts.day === 1
    ? formatDateParts(toParts)
    : formatDateParts(firstDayOfNextMonth(toParts));

  if (monthTo <= monthFrom) {
    monthTo = formatDateParts(firstDayOfNextMonth(parseDateParts(monthFrom)));
  }

  return { fromDate: monthFrom, toDate: monthTo };
}

const fromSource = rawPayload.fromDate || rawPayload.startDate || rawPayload.from || '';
const toSource = rawPayload.toDate || rawPayload.endDate || rawPayload.to || '';

const endpointSourceIds = extractSourceIdsFromEndpoint(rawPayload.publisherEndpoint || rawPayload.publisherEndpointUrl || '');
const sourceIds = Array.from(new Set([
  ...normalizeIdList(rawPayload.sourceIDs),
  ...normalizeIdList(rawPayload.sourceIds),
  ...normalizeIdList(rawPayload.sourceID),
  ...normalizeIdList(rawPayload.sourceId),
  ...endpointSourceIds,
].filter(Boolean)));
const primarySourceId = sourceIds[0] || '';

const today = new Date();
const fallbackTo = new Date(Date.UTC(today.getUTCFullYear(), today.getUTCMonth(), today.getUTCDate()));
const fallbackFrom = new Date(fallbackTo);
fallbackFrom.setUTCDate(fallbackFrom.getUTCDate() - 89);

const reportType = String(rawPayload.reportType || 'program').toLowerCase().trim() || 'program';
const intervalType = String(rawPayload.intervalType || 'month').toLowerCase().trim() || 'month';

const initialFromDate = toYyyyMmDd(fromSource, fallbackFrom);
const initialToDate = toYyyyMmDd(toSource, fallbackTo);
const normalizedRange = normalizeDateRangeByInterval(initialFromDate, initialToDate, intervalType);

const fromDate = normalizedRange.fromDate;
const toDate = normalizedRange.toDate;
const prevFromDate = shiftYear(fromDate, -1);
const prevToDate = shiftYear(toDate, -1);

const languageCode = String(rawPayload.languageCode || 'EN').toUpperCase().trim();
const currencyCode = String(rawPayload.currencyCode || 'EUR').toUpperCase().trim();
const digitalWalletLimit = Math.max(1, Math.min(1000, parseInt(rawPayload.digitalWalletLimit || '1000', 10) || 1000));
const digitalWalletStatus = String(rawPayload.digitalWalletStatus || '').toUpperCase().trim();
const digitalWalletProgramId = String(rawPayload.digitalWalletProgramId || rawPayload.programId || '').trim();
