function asText(value, fallback = '') {
  if (value === null || value === undefined) return fallback;
  const t = String(value).trim();
  return t || fallback;
}

function normalizeRows(rows) {
  if (!Array.isArray(rows)) return [];
  return rows.map((row) => {
    if (!row || typeof row !== 'object' || Array.isArray(row)) return { Value: asText(row, '-') };
    const out = {};
    for (const [k, v] of Object.entries(row)) out[asText(k, 'Field')] = asText(v, '-');
    return out;
  });
}

function normalizeTablesObject(tables) {
  if (!tables || typeof tables !== 'object' || Array.isArray(tables)) return {};
  const out = {};
  for (const [name, rows] of Object.entries(tables)) {
    out[name] = normalizeRows(rows);
  }
  return out;
}

function parseNumeric(value) {
  const txt = asText(value, '').replace(/[^\d,.\-]/g, '');
  if (!txt) return 0;
  const lastComma = txt.lastIndexOf(',');
  const lastDot = txt.lastIndexOf('.');
  let normalized = txt;
  if (lastComma > -1 && lastDot > -1) {
    normalized = lastComma > lastDot
      ? txt.replace(/\./g, '').replace(',', '.')
      : txt.replace(/,/g, '');
  } else if (lastComma > -1) {
    normalized = txt.replace(',', '.');
  }
  const n = Number(normalized);
  return Number.isFinite(n) ? n : 0;
}

function sortProgramBreakdown(rows) {
  const normalized = normalizeRows(rows);
  if (!normalized.length) return [];
  const ordered = normalized
    .slice()
    .sort((a, b) => {
      const aConversions = parseNumeric(a.Conversions || a.Sales);
      const bConversions = parseNumeric(b.Conversions || b.Sales);
      const aOrderValue = parseNumeric(a['Order Value']);
      const bOrderValue = parseNumeric(b['Order Value']);
      const aCommission = parseNumeric(a['Publisher Commission'] || a.Commission);
      const bCommission = parseNumeric(b['Publisher Commission'] || b.Commission);
      const aDigitalWallet = parseNumeric(a['Digital Wallet']);
      const bDigitalWallet = parseNumeric(b['Digital Wallet']);
      const aTotalEarnings = parseNumeric(a['Total Earnings']) || (aCommission + aDigitalWallet);
      const bTotalEarnings = parseNumeric(b['Total Earnings']) || (bCommission + bDigitalWallet);
      const aLowSignal = aConversions <= 0 && aOrderValue <= 0 && aTotalEarnings <= 0 && aCommission <= 0;
      const bLowSignal = bConversions <= 0 && bOrderValue <= 0 && bTotalEarnings <= 0 && bCommission <= 0;

      if (aLowSignal !== bLowSignal) return aLowSignal ? 1 : -1;
      if (aCommission !== bCommission) return bCommission - aCommission;
      if (aTotalEarnings !== bTotalEarnings) return bTotalEarnings - aTotalEarnings;
      if (aOrderValue !== bOrderValue) return bOrderValue - aOrderValue;
      if (aConversions !== bConversions) return bConversions - aConversions;

      return asText(a['Program Name']).localeCompare(asText(b['Program Name']));
    });
  return ordered;
}

function buildProgramYoYTable(kpiSummaryRows) {
  const rows = normalizeRows(kpiSummaryRows);
  if (!rows.length) return [];

  const pickRow = (label) =>
    rows.find((row) => asText(row.Period).toLowerCase() === label.toLowerCase()) || null;

  const recent = pickRow('Recent');
  const previous = pickRow('Previous');
  const difference = pickRow('Difference');
  const variance = pickRow('% Variance');

  const toMetricRow = (rowLabel, source) => ({
    Row: rowLabel,
    Conversions: asText(source?.Conversions || source?.Sales, '-'),
    ConvRate: asText(source?.['Conv Rate'], '-'),
    OrderValue: asText(source?.['Order Value'], '-'),
    PublCommission: asText(source?.['Publisher Commission'], '-'),
    DigitalWallet: asText(source?.['Digital Wallet'], '-'),
    TotalEarnings: asText(source?.['Total Earnings'], '-'),
    ActivePrograms: asText(source?.['Active Programs'], '-'),
  });

  return [
    toMetricRow('Recent', recent),
    toMetricRow('Previous', previous),
    toMetricRow('Difference', difference),
    toMetricRow('Variance', variance),
  ];
}


function stripMarkdownMarker(line) {
  return asText(line, '')
    .replace(/^\s*[-*•]\s+/, '')
    .replace(/^\s*\d+[.)]\s+/, '')
    .replace(/^\s*>\s*/, '')
    .trim();
}

function extractAiSectionLines(markdown, sectionNames, maxLines = 10) {
  const names = (Array.isArray(sectionNames) ? sectionNames : [sectionNames])
    .map((name) => asText(name).toLowerCase())
    .filter(Boolean);
  if (!names.length) return [];

  const lines = asText(markdown).split(/\r?\n/);
  const out = [];
  let inSection = false;
  let sectionLevel = 0;

  for (const rawLine of lines) {
    const line = asText(rawLine);
    const heading = line.match(/^(#{1,6})\s+(.+)$/);
    if (heading) {
      const level = heading[1].length;
      const title = asText(heading[2]).toLowerCase();
      if (inSection && level <= sectionLevel) break;
      if (names.some((name) => title.includes(name))) {
        inSection = true;
        sectionLevel = level;
      }
      continue;
    }

    if (!inSection) continue;
    const cleaned = stripMarkdownMarker(line);
    if (!cleaned || /^[-*_]{3,}$/.test(cleaned)) continue;
    if (/^(reporting period|program level analysis|movers|risks and dependencies)\b/i.test(cleaned)) continue;
    out.push(cleaned);
    if (out.length >= maxLines) break;
  }

  return out;
}

function uniqueLines(lines) {
  const seen = new Set();
  const out = [];
  for (const line of lines || []) {
    const cleaned = asText(line);
    const key = cleaned.toLowerCase();
    if (!cleaned || seen.has(key)) continue;
    seen.add(key);
    out.push(cleaned);
  }
  return out;
}

const languageCode = asText(payload.languageCode, 'EN').toUpperCase();
const languageMap = {
