const programYoYTable = buildProgramYoYTable(publisherTables.kpiSummaryTable || []);
const programScopeTable = publisherTables.programLevelBreakdown || [];
const allProgramsApiScopeTable = normalizeRows(publisherTables.allProgramsApiScope || []);

const slideBlueprint = [
