  { slide: 8, key: 'brand_new_programs', title: 'Brand New Programs' },
  { slide: 9, key: 'sales_growth_risk_dependencies', title: 'Conversion Growth Signals & Risk and Dependencies' },
  { slide: 10, key: 'thank_you', title: 'Thank You' },
];

const requestedSlidesRaw = payload.n_slides ?? payload.targetSlides ?? payload.target_slides;
const requestedSlidesNum = Number(requestedSlidesRaw);
const targetSlides = Number.isFinite(requestedSlidesNum) && requestedSlidesNum > 0
  ? Math.min(Math.floor(requestedSlidesNum), slideBlueprint.length)
  : slideBlueprint.length;

const slideTableBindings = {
  kpi_summary_table: 'kpiSummaryTable + kpiVarianceColorHintsTable',
  program_level_analysis: 'programLevelBreakdown (display subset from API) + allProgramsApiScope (full API scope)',
  kpi_highlights: 'kpiHighlightsTable + kpiHighlightNarrativeTable',
  movers_commission: 'moversShakersCommission',
  movers_sales: 'moversShakersSales',
  brand_new_programs: 'brandNewProgramsTable',
  sales_growth_risk_dependencies: 'salesGrowthSignalsTable + riskDependenciesTable',
};

const baseAdditionalInstructions = asText(
  payload.presentonAdditionalInstructions ||
