  payload.gammaAdditionalInstructions ||
  payload.gamma_additional_instructions ||
  ''
);

const presentonAdditionalInstructions = [
  baseAdditionalInstructions,
  'Clone advertiser QBR layout style for publisher deck only. Do not use advertiser data.',
  'Do not create slides called Publisher Performance Overview or Publisher Segment Analysis.',
  'Slide 1 cover title must be "' + client + ' performance review"; never use "affiliate program" wording.',
